#include<bits/stdc++.h>
using namespace std;
#define endl '\n'

const int maxn=2e3+10;

int n,m,vis[maxn],ans;
vector<int> e[maxn];

int bfs(int s){ //s能到达的点的数量 
	fill(vis,vis+n+2,0);//清空 vis
	queue<int>q;
	q.push(s),vis[s]=1;
	int cot=0;
	while(q.size()){
		int fa=q.front();q.pop();
		cot++;
//		for(int son=0;son<e[fa].size();son++){//遍历 fa的临点 
//			if(vis[e[fa][son]]==0){//fa->i边没有被访问过 
//				q.push(e[fa][son]);
//				vis[e[fa][son]]=1;
//			}
//		}
		for(auto i:e[fa]){
			if(vis[i]==0){
				q.push(i);
				vis[i]=1;
			}
		}


	}
	return cot;
}
/*若 a 到 b 有路径且 b 到 c 有路径，那么 a 和 c 必须有一条有向边连接
即 若 a 到 c 有路径，那么 a 和 c 必须有一条有向边连接
现对于每个点 a，跑一遍 BFS，统计一下 a 能到达的点的数量，减去 a 直接连接的点数连接的点数（图无重边）即为这个点的答案
*/
int main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n>>m;
	for(int i=1,x,y;i<=m;i++){
		cin>>x>>y;
		e[x].emplace_back(y);
	}
	for(int i=1;i<=n;i++){
		ans+=bfs(i)-1-e[i].size();
	}
	cout<<ans;
	return 0;
}
